import json
import sys
import subprocess

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    # Only trigger on Edit events
    if tool != "Edit":
        return 0

    # Only trigger on Python files
    file_path = inp.get("file_path", "")
    if not file_path.endswith(".py"):
        return 0

    # Run ruff format on the edited file
    try:
        subprocess.run(
            ["ruff", "format", file_path],
            capture_output=True,
            timeout=10,
        )
    except Exception:
        # Silently ignore errors (ruff not installed, file not found, etc.)
        pass

    return 0

if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""After Edit/MultiEdit on a line that defines an exported identifier, grep
for callers and feed the list back to Claude so it can verify consistency."""
import json, re, subprocess, sys

EXPORT_DEF = re.compile(
    r"export\s+(?:const|let|var|function|class|type|interface|enum)\s+(\w+)"
)

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0
    if ev.get("tool_name") not in ("Edit", "MultiEdit"):
        return 0
    inp = ev.get("tool_input") or {}
    edits = inp.get("edits") or [
        {"old_string": inp.get("old_string", ""), "new_string": inp.get("new_string", "")}
    ]

    names: set[str] = set()
    for e in edits:
        for s in (e.get("old_string", ""), e.get("new_string", "")):
            m = EXPORT_DEF.search(s)
            if m:
                names.add(m.group(1))

    if not names:
        return 0

    project_dir = ev.get("cwd", ".")
    for name in names:
        try:
            r = subprocess.run(
                ["grep", "-rn", "--include=*.ts", "--include=*.tsx",
                 "--include=*.js", "--include=*.jsx", name, project_dir],
                capture_output=True, text=True, timeout=5,
            )
            hits = [l for l in r.stdout.splitlines() if l][:20]
            if hits:
                print(f"REQUIRED FOLLOW-UP: export `{name}` was edited. {len(hits)} references found:", file=sys.stderr)
                for h in hits:
                    print(f"  {h}", file=sys.stderr)
                print("Fix each occurrence, then summarize. Do not stop.", file=sys.stderr)
                return 2
        except Exception:
            pass
    return 0

if __name__ == "__main__":
    sys.exit(main())

import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool == "WebFetch":
        url = inp.get("url", "").lower()
        if "staging-api.internal" in url:
            print(
                "WebFetch to staging-api.internal is blocked — this is a shared environment "
                "where mutating endpoints affect all team members. Use local mock servers or "
                "recorded fixtures instead.",
                file=sys.stderr
            )
            return 2

    return 0

if __name__ == "__main__":
    sys.exit(main())

