#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool  = ev.get("tool_name", "")
    inp   = ev.get("tool_input") or {}

    if tool != "Bash":
        return 0

    cmd = inp.get("command", "")
    if cmd.strip().startswith("pnpm test") and "test:ci" not in cmd:
        print("Use `pnpm test:ci` instead — `pnpm test` opens an interactive watcher and won't return.", file=sys.stderr)
        return 2
    return 0

if __name__ == "__main__":
    sys.exit(main())

import json
import sys
import os

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0

    tool = ev.get("tool_name", "")
    inp = ev.get("tool_input") or {}

    if tool != "Edit":
        return 0

    filepath = inp.get("file_path", "")
    if not filepath.endswith(".py"):
        return 0

    if not os.path.isfile(filepath):
        return 0

    # Check Python syntax
    try:
        with open(filepath, 'r') as f:
            compile(f.read(), filepath, 'exec')
    except SyntaxError as e:
        print(f"Syntax error in {filepath}: {e.msg} at line {e.lineno}", file=sys.stderr)
        print("REQUIRED FOLLOW-UP: Fix syntax errors before proceeding.", file=sys.stderr)
        return 2
    except Exception:
        return 0

    return 0

if __name__ == "__main__":
    sys.exit(main())
